import React from 'react';
import { TradingViewChart } from './TradingViewChart';
import { LightweightChart } from './LightweightChart';

export interface ChartContainerProps {
  chartType: 'tradingview' | 'lightweight';
  symbol: string;
  theme?: 'light' | 'dark';
  chartData?: { time: string; open: number; high: number; low: number; close: number }[];
  className?: string;
}

export function ChartContainer({ chartType, symbol, theme = 'dark', chartData, className = '' }: ChartContainerProps) {
  return (
    <div className={`ct-relative ct-w-full ct-h-full ${className}`}>
      {chartType === 'tradingview' ? (
        <TradingViewChart symbol={symbol} theme={theme} />
      ) : (
        <LightweightChart data={chartData} theme={theme} />
      )}
    </div>
  );
}
