import React, { useState, useCallback, useEffect } from 'react';
import { useTransfer } from '../../hooks/useTransfer';
import { useTokens } from '../../hooks/useTokens';
import { TokenSelector } from '../swap/TokenSelector';
import { LoadingSpinner } from '../shared/LoadingSpinner';
import { ErrorMessage } from '../shared/ErrorMessage';
import type { TokenRecord } from '../../types';

export interface TransferFormProps {
  walletAddress?: string;
  onSign?: (transaction: string) => Promise<string>;
  onSuccess?: (signature: string) => void;
  onError?: (error: string) => void;
  className?: string;
}

const SOL_MINT = 'So11111111111111111111111111111111111111112';

export function TransferForm({ walletAddress, onSign, onSuccess, onError, className = '' }: TransferFormProps) {
  const { buildResult, isLoading, error, build, execute, resolveAddress, reset } = useTransfer();

  const [recipient, setRecipient] = useState('');
  const [amount, setAmount] = useState('');
  const [selectedToken, setSelectedToken] = useState<TokenRecord | null>(null);
  const [mint, setMint] = useState(SOL_MINT);
  const [selectorOpen, setSelectorOpen] = useState(false);
  const [resolvedAddress, setResolvedAddress] = useState<string | null>(null);
  const [step, setStep] = useState<'form' | 'sign' | 'done'>('form');

  // Resolve .sol domains
  useEffect(() => {
    if (!recipient.endsWith('.sol')) {
      setResolvedAddress(null);
      return;
    }
    const timer = setTimeout(async () => {
      try {
        const r = await resolveAddress(recipient);
        setResolvedAddress(r.resolved);
      } catch { setResolvedAddress(null); }
    }, 500);
    return () => clearTimeout(timer);
  }, [recipient, resolveAddress]);

  const handleTokenSelect = useCallback((token: TokenRecord) => {
    setSelectedToken(token);
    setMint(token.mint);
  }, []);

  const handleSend = useCallback(async () => {
    if (!walletAddress || !onSign) return;
    try {
      setStep('sign');
      const decimals = selectedToken?.decimals ?? 9;
      const rawAmount = Math.round(parseFloat(amount) * Math.pow(10, decimals)).toString();
      const result = await build(walletAddress, recipient, mint, rawAmount);

      const signedTx = await onSign(result.transaction);
      const execResult = await execute(signedTx);
      setStep('done');
      onSuccess?.(execResult.signature);
    } catch (e: any) {
      setStep('form');
      onError?.(e.message);
    }
  }, [walletAddress, onSign, amount, recipient, mint, selectedToken, build, execute, onSuccess, onError]);

  return (
    <div className={`ct-bg-[hsl(var(--cedros-background))] ct-border ct-border-[hsl(var(--cedros-border))] ct-rounded-cedros ct-p-4 ct-space-y-4 ${className}`}>
      <h3 className="ct-text-lg ct-font-semibold ct-text-[hsl(var(--cedros-foreground))]">Send</h3>

      {/* Recipient */}
      <div className="ct-space-y-1">
        <label className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">Recipient</label>
        <input type="text" value={recipient} onChange={e => setRecipient(e.target.value)}
          placeholder="Wallet address or name.sol"
          className="ct-w-full ct-px-3 ct-py-3 ct-rounded-cedros ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))] ct-outline-none focus:ct-ring-2 focus:ct-ring-[hsl(var(--cedros-ring))]" />
        {resolvedAddress && (
          <div className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">
            Resolves to: <span className="ct-font-mono">{resolvedAddress.slice(0, 8)}...{resolvedAddress.slice(-4)}</span>
          </div>
        )}
      </div>

      {/* Token + Amount */}
      <div className="ct-space-y-1">
        <label className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">Amount</label>
        <div className="ct-flex ct-gap-2">
          <input type="text" value={amount} onChange={e => setAmount(e.target.value)} placeholder="0.00"
            className="ct-flex-1 ct-px-3 ct-py-3 ct-rounded-cedros ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-xl ct-text-[hsl(var(--cedros-foreground))] ct-outline-none focus:ct-ring-2 focus:ct-ring-[hsl(var(--cedros-ring))]" />
          <button onClick={() => setSelectorOpen(true)}
            className="ct-px-4 ct-py-3 ct-rounded-cedros ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))] hover:ct-bg-[hsl(var(--cedros-border))] ct-font-medium ct-min-w-[100px]">
            {selectedToken?.symbol ?? 'SOL'}
          </button>
        </div>
      </div>

      {/* ATA creation warning */}
      {buildResult?.createsAta && (
        <div className="ct-rounded-cedros ct-bg-yellow-500/10 ct-border ct-border-yellow-500/20 ct-px-3 ct-py-2 ct-text-xs ct-text-yellow-400">
          This will create a token account for the recipient (~0.002 SOL rent).
        </div>
      )}

      <ErrorMessage message={error} onDismiss={reset} />

      <button onClick={handleSend}
        disabled={!walletAddress || !recipient || !amount || isLoading || step !== 'form'}
        className="ct-w-full ct-py-3 ct-rounded-cedros ct-font-semibold ct-text-[hsl(var(--cedros-primary-foreground))] ct-bg-[hsl(var(--cedros-primary))] hover:ct-opacity-90 disabled:ct-opacity-50 disabled:ct-cursor-not-allowed ct-transition">
        {!walletAddress ? 'Connect Wallet' :
         step === 'sign' ? 'Signing...' :
         step === 'done' ? 'Sent!' :
         isLoading ? <LoadingSpinner /> : 'Send'}
      </button>

      <TokenSelector isOpen={selectorOpen} onClose={() => setSelectorOpen(false)} onSelect={handleTokenSelect} />
    </div>
  );
}
