import React, { useState, useCallback, useEffect } from 'react';
import type { TokenRecord, SwapQuote } from '../../types';
import { useSwap } from '../../hooks/useSwap';
import { TokenSelector } from './TokenSelector';
import { SlippageControl } from './SlippageControl';
import { LoadingSpinner } from '../shared/LoadingSpinner';
import { ErrorMessage } from '../shared/ErrorMessage';

export interface SwapFormProps {
  /** User's wallet public key */
  walletAddress?: string;
  /** Called with the unsigned transaction for signing */
  onSign?: (transaction: string, provider: string, requestId?: string) => Promise<string>;
  /** Called after successful execution */
  onSuccess?: (signature: string) => void;
  onError?: (error: string) => void;
  defaultInputMint?: string;
  defaultOutputMint?: string;
  /** Restrict which mints appear in the input token selector */
  allowedInputMints?: string[];
  /** Restrict which mints appear in the output token selector */
  allowedOutputMints?: string[];
  className?: string;
}

const SOL_MINT = 'So11111111111111111111111111111111111111112';
const USDC_MINT = 'EPjFWdd5AufqSSqeM2qN1xzybapC8G4wEGGkZwyTDt1v';

export function SwapForm({
  walletAddress, onSign, onSuccess, onError,
  defaultInputMint = SOL_MINT, defaultOutputMint = USDC_MINT,
  allowedInputMints, allowedOutputMints,
  className = '',
}: SwapFormProps) {
  const { quote, isLoading, error, getQuote, buildTransaction, execute, reset } = useSwap();

  const [inputToken, setInputToken] = useState<TokenRecord | null>(null);
  const [outputToken, setOutputToken] = useState<TokenRecord | null>(null);
  const [inputMint, setInputMint] = useState(defaultInputMint);
  const [outputMint, setOutputMint] = useState(defaultOutputMint);
  const [amount, setAmount] = useState('');
  const [slippageBps, setSlippageBps] = useState(50);
  const [selectorSide, setSelectorSide] = useState<'input' | 'output' | null>(null);
  const [step, setStep] = useState<'quote' | 'sign' | 'done'>('quote');

  // Debounced quote fetch
  useEffect(() => {
    if (!amount || !inputMint || !outputMint) return;
    const timer = setTimeout(() => {
      getQuote(inputMint, outputMint, amount, slippageBps).catch(() => {});
    }, 500);
    return () => clearTimeout(timer);
  }, [amount, inputMint, outputMint, slippageBps, getQuote]);

  const handleSwapDirection = useCallback(() => {
    setInputMint(outputMint);
    setOutputMint(inputMint);
    const tmp = inputToken;
    setInputToken(outputToken);
    setOutputToken(tmp);
    setAmount('');
    reset();
  }, [inputMint, outputMint, inputToken, outputToken, reset]);

  const handleSelectToken = useCallback((token: TokenRecord) => {
    if (selectorSide === 'input') {
      setInputMint(token.mint);
      setInputToken(token);
    } else {
      setOutputMint(token.mint);
      setOutputToken(token);
    }
    reset();
  }, [selectorSide, reset]);

  const handleSwap = useCallback(async () => {
    if (!quote || !walletAddress || !onSign) return;
    try {
      setStep('sign');
      const tx = await buildTransaction(quote, walletAddress);
      const signedTx = await onSign(tx.transaction, quote.provider, tx.requestId ?? undefined);
      const result = await execute(signedTx, quote.provider, tx.requestId ?? undefined);
      setStep('done');
      onSuccess?.(result.signature);
    } catch (e: any) {
      setStep('quote');
      onError?.(e.message);
    }
  }, [quote, walletAddress, onSign, buildTransaction, execute, onSuccess, onError]);

  const formatOutput = (q: SwapQuote | null) => {
    if (!q) return '';
    const decimals = outputToken?.decimals ?? 6;
    return (parseInt(q.outAmount) / Math.pow(10, decimals)).toFixed(decimals > 4 ? 4 : decimals);
  };

  return (
    <div className={`ct-bg-[hsl(var(--cedros-background))] ct-border ct-border-[hsl(var(--cedros-border))] ct-rounded-cedros ct-p-4 ct-space-y-4 ${className}`}>
      <h3 className="ct-text-lg ct-font-semibold ct-text-[hsl(var(--cedros-foreground))]">Swap</h3>

      {/* Input */}
      <div className="ct-space-y-1">
        <label className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">You pay</label>
        <div className="ct-flex ct-gap-2">
          <input type="text" value={amount} onChange={e => setAmount(e.target.value)} placeholder="0.00"
            className="ct-flex-1 ct-px-3 ct-py-3 ct-rounded-cedros ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-xl ct-text-[hsl(var(--cedros-foreground))] ct-outline-none focus:ct-ring-2 focus:ct-ring-[hsl(var(--cedros-ring))]" />
          <button onClick={() => setSelectorSide('input')}
            className="ct-px-4 ct-py-3 ct-rounded-cedros ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))] hover:ct-bg-[hsl(var(--cedros-border))] ct-font-medium ct-min-w-[100px]">
            {inputToken?.symbol ?? 'SOL'}
          </button>
        </div>
      </div>

      {/* Swap direction */}
      <div className="ct-flex ct-justify-center">
        <button onClick={handleSwapDirection}
          className="ct-p-2 ct-rounded-full ct-bg-[hsl(var(--cedros-muted))] hover:ct-bg-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-muted-foreground))] ct-transition">
          ↕
        </button>
      </div>

      {/* Output */}
      <div className="ct-space-y-1">
        <label className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">You receive</label>
        <div className="ct-flex ct-gap-2">
          <div className="ct-flex-1 ct-px-3 ct-py-3 ct-rounded-cedros ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-xl ct-text-[hsl(var(--cedros-foreground))]">
            {isLoading ? <LoadingSpinner /> : formatOutput(quote)}
          </div>
          <button onClick={() => setSelectorSide('output')}
            className="ct-px-4 ct-py-3 ct-rounded-cedros ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))] hover:ct-bg-[hsl(var(--cedros-border))] ct-font-medium ct-min-w-[100px]">
            {outputToken?.symbol ?? 'USDC'}
          </button>
        </div>
      </div>

      {/* Quote details */}
      {quote && (
        <div className="ct-space-y-1 ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">
          <div className="ct-flex ct-justify-between">
            <span>Provider</span>
            <span className="ct-capitalize">{quote.provider} {quote.gasless && '(gasless)'}</span>
          </div>
          <div className="ct-flex ct-justify-between">
            <span>Price impact</span>
            <span className={quote.priceImpactPct > 1 ? 'ct-text-red-400' : ''}>{quote.priceImpactPct.toFixed(2)}%</span>
          </div>
          {quote.otherAmountThreshold && (
            <div className="ct-flex ct-justify-between">
              <span>Min received</span>
              <span>{(parseInt(quote.otherAmountThreshold) / Math.pow(10, outputToken?.decimals ?? 6)).toFixed(4)}</span>
            </div>
          )}
        </div>
      )}

      <SlippageControl value={slippageBps} onChange={setSlippageBps} />

      <ErrorMessage message={error} onDismiss={reset} />

      {/* Swap button */}
      <button onClick={handleSwap} disabled={!quote || !walletAddress || isLoading || step !== 'quote'}
        className="ct-w-full ct-py-3 ct-rounded-cedros ct-font-semibold ct-text-[hsl(var(--cedros-primary-foreground))] ct-bg-[hsl(var(--cedros-primary))] hover:ct-opacity-90 disabled:ct-opacity-50 disabled:ct-cursor-not-allowed ct-transition">
        {!walletAddress ? 'Connect Wallet' :
         step === 'sign' ? 'Signing...' :
         step === 'done' ? 'Swap Complete' :
         isLoading ? 'Fetching Quote...' :
         !quote ? 'Enter Amount' : 'Swap'}
      </button>

      {/* Token Selector Modal */}
      <TokenSelector
        isOpen={selectorSide !== null}
        onClose={() => setSelectorSide(null)}
        onSelect={handleSelectToken}
        excludeMints={selectorSide === 'input' ? [outputMint] : [inputMint]}
        allowedMints={selectorSide === 'input' ? allowedInputMints : allowedOutputMints}
      />
    </div>
  );
}
